import{_ as t,o as a,c as o,a0 as r}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"Documento de Visão — NEXUS","description":"","frontmatter":{},"headers":[],"relativePath":"10_Fundacao/vision.md","filePath":"10_Fundacao/vision.md","lastUpdated":1783623176000}'),s={name:"10_Fundacao/vision.md"};function d(i,e,n,l,c,m){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="documento-de-visao-—-nexus" tabindex="-1">Documento de Visão — NEXUS <a class="header-anchor" href="#documento-de-visao-—-nexus" aria-label="Permalink to &quot;Documento de Visão — NEXUS&quot;">​</a></h1><p><strong>Versão:</strong> 1.0 — Junho de 2026<br><strong>Status:</strong> Rascunho</p><hr><h2 id="_1-introducao" tabindex="-1">1. Introdução <a class="header-anchor" href="#_1-introducao" aria-label="Permalink to &quot;1. Introdução&quot;">​</a></h2><h3 id="_1-1-proposito" tabindex="-1">1.1 Propósito <a class="header-anchor" href="#_1-1-proposito" aria-label="Permalink to &quot;1.1 Propósito&quot;">​</a></h3><p>Este documento define a visão de alto nível do <strong>NEXUS — Multi-Relational Graph Runtime for LLM External Memory</strong>. Ele descreve o problema que o sistema resolve, os stakeholders envolvidos, as capacidades essenciais e a proposta de valor do produto.</p><h3 id="_1-2-escopo" tabindex="-1">1.2 Escopo <a class="header-anchor" href="#_1-2-escopo" aria-label="Permalink to &quot;1.2 Escopo&quot;">​</a></h3><p>O NEXUS é um sistema de memória externa para agentes de IA (LLMs) que combina busca semântica vetorial com navegação topológica em grafo multi-relacional. O sistema permite que agentes de IA naveguem em bases de código complexas sem depender de busca por força bruta (<code>grep</code>/<code>find</code>/loops de leitura), reduzindo deriva semântica e preservando contexto operacional.</p><h3 id="_1-3-definicoes" tabindex="-1">1.3 Definições <a class="header-anchor" href="#_1-3-definicoes" aria-label="Permalink to &quot;1.3 Definições&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Termo</th><th>Definição</th></tr></thead><tbody><tr><td><strong>T1</strong></td><td>Filesystem — fonte de verdade original dos artefatos</td></tr><tr><td><strong>T2</strong></td><td>PostgreSQL — âncora canônica de dados estruturados</td></tr><tr><td><strong>T3</strong></td><td>Qdrant — entrada por proximidade vetorial (embeddings)</td></tr><tr><td><strong>T4</strong></td><td>Grafo Multi-Relacional — navegação topológica</td></tr><tr><td><strong>L0</strong></td><td>Chunks brutos de código fonte</td></tr><tr><td><strong>L1</strong></td><td>Abstração estrutural via AST (ast-grep)</td></tr><tr><td><strong>L2</strong></td><td>Abstração semântica via LLM (Ollama)</td></tr><tr><td><strong>L3</strong></td><td>Síntese arquitetural emergente do grafo</td></tr><tr><td><strong>MCP</strong></td><td>Model Context Protocol — interface de comunicação com agentes</td></tr></tbody></table><hr><h2 id="_2-contexto-de-negocio" tabindex="-1">2. Contexto de Negócio <a class="header-anchor" href="#_2-contexto-de-negocio" aria-label="Permalink to &quot;2. Contexto de Negócio&quot;">​</a></h2><h3 id="_2-1-o-problema" tabindex="-1">2.1 O Problema <a class="header-anchor" href="#_2-1-o-problema" aria-label="Permalink to &quot;2.1 O Problema&quot;">​</a></h3><p>Agentes de IA modernos (LLMs) enfrentam limitações críticas ao navegar em bases de código complexas:</p><ol><li><strong>Janela de contexto limitada</strong> — impossível carregar uma base de código inteira.</li><li><strong>Deriva semântica</strong> — o agente alucina estruturas que não existem.</li><li><strong>Custo de busca</strong> — loops de <code>grep</code>/<code>find</code> consomem tokens e janela de contexto.</li><li><strong>Perda de memória operacional</strong> — soluções passadas são esquecidas entre sessões.</li><li><strong>Falta de navegação topológica</strong> — busca semântica plana não entende hierarquia de código.</li></ol><h3 id="_2-2-a-solucao" tabindex="-1">2.2 A Solução <a class="header-anchor" href="#_2-2-a-solucao" aria-label="Permalink to &quot;2.2 A Solução&quot;">​</a></h3><p>O NEXUS resolve esses problemas através de uma arquitetura bipartida:</p><ul><li><strong>T3 (GPS Semântico)</strong> — embeddings vetoriais em espaço 768d que entendem intenção e proximidade semântica. O agente pergunta &quot;onde fica a lógica de agendamento?&quot; e o GPS aponta a vizinhança.</li><li><strong>T4 (Mapa da Cidade)</strong> — grafo multi-relacional hierárquico com arestas de hierarquia (<code>part_of</code>), dependência (<code>depends_on:imports</code>), similaridade (<code>semantic_bridge</code>) e conflito (<code>contradicts</code>). O agente navega pela estrutura real do código.</li></ul><h3 id="_2-3-stakeholders" tabindex="-1">2.3 Stakeholders <a class="header-anchor" href="#_2-3-stakeholders" aria-label="Permalink to &quot;2.3 Stakeholders&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stakeholder</th><th>Interesse</th></tr></thead><tbody><tr><td><strong>Agentes de IA</strong></td><td>Consumidores primários da API MCP; usam NEXUS para navegar codebases</td></tr><tr><td><strong>Desenvolvedores</strong></td><td>Usam o sistema indiretamente através de ferramentas MCP</td></tr><tr><td><strong>Arquitetos</strong></td><td>Decisões arquiteturais registradas como ADRs, consultáveis via <code>nexus_reflections</code></td></tr><tr><td><strong>Operadores</strong></td><td>Gerenciam a stack (Docker/Podman), monitoram pipeline, aplicam bugfixes</td></tr><tr><td><strong>Pesquisadores</strong></td><td>Exploram dinâmicas de swarm, teoria de grafos, compressão semântica</td></tr></tbody></table><hr><h2 id="_3-visao-geral-do-produto" tabindex="-1">3. Visão Geral do Produto <a class="header-anchor" href="#_3-visao-geral-do-produto" aria-label="Permalink to &quot;3. Visão Geral do Produto&quot;">​</a></h2><h3 id="_3-1-arquitetura-em-uma-linha" tabindex="-1">3.1 Arquitetura em Uma Linha <a class="header-anchor" href="#_3-1-arquitetura-em-uma-linha" aria-label="Permalink to &quot;3.1 Arquitetura em Uma Linha&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T1 Filesystem → T2 PostgreSQL → T3 Qdrant → T4 Multi-Relational Graph → T5 Reflections → T6 Time</span></span></code></pre></div><h3 id="_3-2-capacidades-essenciais" tabindex="-1">3.2 Capacidades Essenciais <a class="header-anchor" href="#_3-2-capacidades-essenciais" aria-label="Permalink to &quot;3.2 Capacidades Essenciais&quot;">​</a></h3><ol><li><strong>Ingestão Multi-Repo</strong>: Monitora mudanças no filesystem, ingere novos arquivos e atualiza automaticamente o grafo.</li><li><strong>Pipeline de Abstração em 3 Níveis</strong>: <ul><li>L0: Chunking determinístico por limites naturais (AST-aware).</li><li>L1: Extração estrutural via <code>ast-grep</code> (funções, classes, interfaces).</li><li>L2: Geração de descrições semânticas via LLM local (Ollama).</li></ul></li><li><strong>Navegação Topológica (T4)</strong>: Caminhada multi-relacional com 4 tipos de aresta e 3 eixos de projeção.</li><li><strong>Busca Híbrida (T3 + T4)</strong>: Embedding → seeds vetoriais → expansão no grafo → hidratação de contexto.</li><li><strong>Memória Stigmergic</strong>: Agentes registram descobertas via <code>nexus_link()</code>, criando trilhas para agentes futuros.</li><li><strong>Reflexões Arquiteturais (L3)</strong>: Síntese de domínio emergente por detecção de comunidades no grafo.</li><li><strong>MCP Server</strong>: Interface padronizada SSE para qualquer cliente compatível.</li></ol><h3 id="_3-3-proposta-de-valor" tabindex="-1">3.3 Proposta de Valor <a class="header-anchor" href="#_3-3-proposta-de-valor" aria-label="Permalink to &quot;3.3 Proposta de Valor&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Para</th><th>Valor</th></tr></thead><tbody><tr><td><strong>Agentes de IA</strong></td><td>Navegação precisa sem brute-force; redução de alucinações estruturais</td></tr><tr><td><strong>Desenvolvedores</strong></td><td>Contexto operacional preservado entre sessões; descoberta de código por intenção</td></tr><tr><td><strong>Arquitetos</strong></td><td>Decisões arquiteturais rastreáveis; detecção de deriva semântica</td></tr><tr><td><strong>Operadores</strong></td><td>Stack auto-contida; observabilidade via endpoints de status</td></tr></tbody></table><hr><h2 id="_4-premissas-e-dependencias" tabindex="-1">4. Premissas e Dependências <a class="header-anchor" href="#_4-premissas-e-dependencias" aria-label="Permalink to &quot;4. Premissas e Dependências&quot;">​</a></h2><h3 id="_4-1-premissas" tabindex="-1">4.1 Premissas <a class="header-anchor" href="#_4-1-premissas" aria-label="Permalink to &quot;4.1 Premissas&quot;">​</a></h3><ol><li><strong>Ollama como motor de inferência local</strong> — modelo <code>qwen2.5-coder:nexus</code> para geração L2/L3, <code>nomic-embed-text</code> para embeddings.</li><li><strong>GPU NVIDIA disponível (mín. 6GB VRAM)</strong> — GTX 1660S, 29 layers offloaded.</li><li><strong>PostgreSQL 16 com pgvector</strong> — schema evolutivo via migrations.</li><li><strong>Qdrant como store vetorial</strong> — coleções nomeadas com vetor <code>text_dense</code> (768d, Cosine).</li><li><strong>Rust como linguagem de implementação</strong> — performance e segurança de memória.</li><li><strong>ast-grep como extrator estrutural</strong> — análise sintática determinística.</li></ol><h3 id="_4-2-dependencias-externas" tabindex="-1">4.2 Dependências Externas <a class="header-anchor" href="#_4-2-dependencias-externas" aria-label="Permalink to &quot;4.2 Dependências Externas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dependência</th><th>Papel</th><th>Versão</th></tr></thead><tbody><tr><td>PostgreSQL + pgvector</td><td>Armazenamento canônico</td><td>pg16</td></tr><tr><td>Qdrant</td><td>Store vetorial</td><td>latest</td></tr><tr><td>Ollama</td><td>Inferência LLM local</td><td>latest</td></tr><tr><td>ast-grep</td><td>Extração AST</td><td>binary</td></tr><tr><td>Tokio</td><td>Runtime assíncrono Rust</td><td>1.x</td></tr></tbody></table><hr><h2 id="_5-cronograma-e-marcos" tabindex="-1">5. Cronograma e Marcos <a class="header-anchor" href="#_5-cronograma-e-marcos" aria-label="Permalink to &quot;5. Cronograma e Marcos&quot;">​</a></h2><h3 id="_5-1-estado-atual-junho-2026" tabindex="-1">5.1 Estado Atual (Junho 2026) <a class="header-anchor" href="#_5-1-estado-atual-junho-2026" aria-label="Permalink to &quot;5.1 Estado Atual (Junho 2026)&quot;">​</a></h3><ul><li>✅ Pipeline L0/L1/L2 operacional (Rust)</li><li>✅ Busca semântica T3 (Qdrant)</li><li>✅ Navegação topológica T4 (grafo multi-relacional)</li><li>✅ MCP Server com 7 tools expostas</li><li>✅ Ingestão multi-repositório (filesystem watch)</li><li>✅ L3 síntese arquitetural (básico)</li><li>✅ Snapshots e backup operacionais</li><li>✅ Documentação de operações e guias extraída</li></ul><h3 id="_5-2-proximos-marcos" tabindex="-1">5.2 Próximos Marcos <a class="header-anchor" href="#_5-2-proximos-marcos" aria-label="Permalink to &quot;5.2 Próximos Marcos&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Marco</th><th>Descrição</th><th>Status</th></tr></thead><tbody><tr><td><strong>ADR-0003</strong></td><td>Nomad Workers — decompor coordinator em loops independentes</td><td>Proposto</td></tr><tr><td><strong>ADR-0024</strong></td><td>Heat Propagation — propagação de calor no grafo T4</td><td>Aceito</td></tr><tr><td><strong>ADR-0023</strong></td><td>Context GC — garbage collection de chunks obsoletos</td><td>Aceito</td></tr><tr><td><strong>ADR-0025</strong></td><td>Vector Typing per Projection — vetores por tipo de projeção</td><td>Pensamento</td></tr><tr><td><strong>ADR-0021</strong></td><td>Forgetful Swarm Dynamics — decaimento stigmergic</td><td>Rascunho</td></tr><tr><td>Federação Remota</td><td>Supabase + PGMQ para runtime híbrido local/remoto</td><td>Roadmap</td></tr></tbody></table><hr><h2 id="_6-riscos-conhecidos" tabindex="-1">6. Riscos Conhecidos <a class="header-anchor" href="#_6-riscos-conhecidos" aria-label="Permalink to &quot;6. Riscos Conhecidos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risco</th><th>Impacto</th><th>Mitigação</th></tr></thead><tbody><tr><td>OOM do Ollama (6GB VRAM limitada)</td><td>Pipeline L2/L3 bloqueado</td><td>Semáforo de 2 permits; monitoramento de memória</td></tr><tr><td>Concorrência no enrichment</td><td>L2 nunca drena → Qdrant vazio</td><td>Background loops isolados; evitar POST /enrich manual</td></tr><tr><td>Deriva de schema Qdrant</td><td>Queries falham silenciosamente</td><td>Schema fixo <code>text_dense</code>; recriação manual documentada</td></tr><tr><td>Fragmentação de contexto</td><td>Agentes perdem trilhas stigmergic</td><td><code>nexus_link()</code> como memória ativa; ADR-0021 (decay)</td></tr><tr><td>Container Ollama sem RAM</td><td>Modelos não carregam</td><td>Limite 8G no docker-compose; 29 layers offloaded</td></tr></tbody></table>',43)])])}const h=t(s,[["render",d]]);export{g as __pageData,h as default};
